		, A.SADM_DPPHONE = #{sadmDpphone, jdbcType=VARCHAR}


		, A.SADM_EMAIL = #{sadmEmail, jdbcType=VARCHAR}


		, A.SCITY = CASE WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '서울' THEN '서울'
							WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '인천' THEN '인천'
							WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '부산' THEN '부산'
							WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '대전' THEN '대전'
							WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '광주' THEN '광주'
							WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '울산' THEN '울산'
							WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '제주' THEN '제주'
							WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '강원' THEN '강원'
							WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '대구' THEN '대구'
							WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '경기' THEN '경기'
							WHEN LEFT(#{saddr, jdbcType=VARCHAR},4) = '충청북도' THEN '충북'
							WHEN LEFT(#{saddr, jdbcType=VARCHAR},4) = '충청남도' THEN '충남'
							WHEN LEFT(#{saddr, jdbcType=VARCHAR},4) = '경상남도' THEN '경남'
							WHEN LEFT(#{saddr, jdbcType=VARCHAR},4) = '경상북도' THEN '경북'
							WHEN LEFT(#{saddr, jdbcType=VARCHAR},4) = '전라남도' THEN '전북'
							WHEN LEFT(#{saddr, jdbcType=VARCHAR},4) = '전라북도' THEN '전남'
							ELSE '경기'
							END 


		, A.SECITY = UPPER(bif.uf_convert_han_to_eng(CASE WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '서울' THEN '서울'
																						WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '인천' THEN '인천'
																						WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '부산' THEN '부산'
																						WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '대전' THEN '대전'
																						WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '광주' THEN '광주'
																						WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '울산' THEN '울산'
																						WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '제주' THEN '제주'
																						WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '강원' THEN '강원'
																						WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '대구' THEN '대구'
																						WHEN LEFT(#{saddr, jdbcType=VARCHAR},2) = '경기' THEN '경기'
																						WHEN LEFT(#{saddr, jdbcType=VARCHAR},4) = '충청북도' THEN '충북'
																						WHEN LEFT(#{saddr, jdbcType=VARCHAR},4) = '충청남도' THEN '충남'
																						WHEN LEFT(#{saddr, jdbcType=VARCHAR},4) = '경상남도' THEN '경남'
																						WHEN LEFT(#{saddr, jdbcType=VARCHAR},4) = '경상북도' THEN '경북'
																						WHEN LEFT(#{saddr, jdbcType=VARCHAR},4) = '전라남도' THEN '전북'
																						WHEN LEFT(#{saddr, jdbcType=VARCHAR},4) = '전라북도' THEN '전남'
																						ELSE '경기'
																						END , 'Y'))

WHERE
	A.SSAID = #{ssaid, jdbcType=VARCHAR}

